INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a86a598d-f117-4b86-8cbc-fd8500f829db', $q$Declarative Pipelines$q$, $q$Pipelines are defined as version-controlled YAML rather than configured through a UI, making them reviewable and reproducible like any other code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a86a598d-f117-4b86-8cbc-fd8500f829db', $q$Resources, Tasks & Jobs Model$q$, $q$A small set of primitives — versioned resources, containerized tasks, and triggered jobs — composes into arbitrarily complex delivery workflows.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a86a598d-f117-4b86-8cbc-fd8500f829db', $q$Container-Based Execution$q$, $q$Every task runs in its own container with an explicit image, isolating dependencies and ensuring builds behave the same across machines.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a86a598d-f117-4b86-8cbc-fd8500f829db', $q$fly CLI for Local Testing$q$, $q$Developers can execute a pipeline task locally with uncommitted changes before pushing, avoiding the push-fail-fix loop common to hosted CI.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a86a598d-f117-4b86-8cbc-fd8500f829db', $q$Custom Resource Types Instead of Plugins$q$, $q$Integrations with external systems are implemented as container images conforming to a simple interface, avoiding a heavyweight plugin ecosystem.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a86a598d-f117-4b86-8cbc-fd8500f829db', $q$Visual Pipeline Dashboard$q$, $q$The web UI renders pipelines as a graph, letting engineers trace a failure from a single click back to its root cause.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a86a598d-f117-4b86-8cbc-fd8500f829db', $q$Multiple Deployment Options$q$, $q$Concourse ships as a standalone binary, a Docker Compose setup, a Kubernetes Helm chart, or a BOSH release for larger deployments.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a86a598d-f117-4b86-8cbc-fd8500f829db', $q$Completely free and open source with no paid tiers or vendor lock-in$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a86a598d-f117-4b86-8cbc-fd8500f829db', $q$Strong reproducibility from fully containerized, isolated task execution$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a86a598d-f117-4b86-8cbc-fd8500f829db', $q$Declarative, git-versioned pipelines avoid UI-configuration sprawl$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a86a598d-f117-4b86-8cbc-fd8500f829db', $q$Scales horizontally via stateless worker nodes$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a86a598d-f117-4b86-8cbc-fd8500f829db', $q$Steeper learning curve than point-and-click CI tools like GitHub Actions$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a86a598d-f117-4b86-8cbc-fd8500f829db', $q$No official managed/SaaS hosting — teams must operate their own infrastructure$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a86a598d-f117-4b86-8cbc-fd8500f829db', $q$Smaller plugin/integration ecosystem than Jenkins$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a86a598d-f117-4b86-8cbc-fd8500f829db', $q$Self-hosting requires running and maintaining PostgreSQL plus web and worker nodes$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a86a598d-f117-4b86-8cbc-fd8500f829db', $q$Is Concourse CI free?$q$, $q$Yes. Concourse is fully open source under the Apache 2.0 license with no paid tiers; you only pay for the infrastructure you run it on.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a86a598d-f117-4b86-8cbc-fd8500f829db', $q$Does Concourse offer a hosted or SaaS version?$q$, $q$No official managed SaaS exists. Concourse is designed to be self-hosted using a standalone binary, Docker Compose, a Helm chart, or a BOSH release.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a86a598d-f117-4b86-8cbc-fd8500f829db', $q$What language is Concourse written in?$q$, $q$The core web component (ATC) and workers are written in Go, while the browser-based dashboard UI is built with Elm.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a86a598d-f117-4b86-8cbc-fd8500f829db', $q$How is Concourse different from Jenkins?$q$, $q$Concourse uses declarative, version-controlled pipeline YAML and fully containerized task execution instead of Jenkins' UI-configured jobs and plugin ecosystem.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a86a598d-f117-4b86-8cbc-fd8500f829db', $q$Can I test a pipeline task locally before pushing?$q$, $q$Yes, the fly CLI's execute command runs a task locally with your uncommitted changes, letting you debug before committing.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a86a598d-f117-4b86-8cbc-fd8500f829db', $q$CI/CD for Containerized Applications$q$, $q$Teams building containerized services use Concourse's fully isolated task execution to get reproducible builds across environments.$q$, $q$DevOps and platform engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a86a598d-f117-4b86-8cbc-fd8500f829db', $q$Custom Multi-Tool Delivery Pipelines$q$, $q$Organizations needing to integrate many internal or uncommon tools build custom resource types instead of waiting on a plugin marketplace.$q$, $q$Engineering teams with bespoke infrastructure$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a86a598d-f117-4b86-8cbc-fd8500f829db', $q$Open Source (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Apache 2.0 license","Unlimited pipelines, jobs, and workers","Standalone binary, Docker Compose, Helm chart, or BOSH release deployment","Community support via GitHub Discussions and Discord"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a86a598d-f117-4b86-8cbc-fd8500f829db', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Concourse CI is a free, open-source automation system focused on CI/CD, originally built in 2014 by engineers on Pivotal's Cloud Foundry team who were dissatisfied with Jenkins' plugin-driven, UI-configured pipelines. It was open sourced in 2015 and remains fully community- and sponsor-supported, with no paid tier or official hosted service.$q$, $q$The project treats pipelines as first-class, version-controlled artifacts defined in declarative YAML rather than assembled through a web UI. Every build step runs inside an isolated container, giving Concourse strong guarantees around reproducibility and idempotency that distinguish it from more traditional, stateful CI servers.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a86a598d-f117-4b86-8cbc-fd8500f829db', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Pipelines are built from three primitives: resources (versioned inputs and outputs like Git repositories or container images), tasks (containerized units of work), and jobs (sequences of tasks triggered by resource changes). This model lets Concourse express complex, multi-stage delivery workflows without a plugin marketplace — new integrations are just container images implementing a simple resource interface.$q$, $q$The fly CLI lets developers run a task locally with uncommitted changes before pushing, shortening the feedback loop, while the web UI visualizes pipelines as a graph for tracing failures back to their source. Concourse can be installed as a standalone binary, via Docker Compose, through a Kubernetes Helm chart, or as a BOSH release, with PostgreSQL as the backing database.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a86a598d-f117-4b86-8cbc-fd8500f829db', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Concourse CI is entirely free and open source under the Apache 2.0 license — there are no paid plans, seat limits, or usage caps imposed by the project itself. The only real cost is the infrastructure a team provisions to run the web, worker, and PostgreSQL nodes.$q$, $q$Because there is no official managed SaaS offering, organizations that don't want to operate their own Concourse deployment typically look to hosted CI alternatives instead; Concourse is aimed squarely at teams willing to self-host in exchange for full control over their pipeline infrastructure.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a86a598d-f117-4b86-8cbc-fd8500f829db', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a86a598d-f117-4b86-8cbc-fd8500f829db', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a86a598d-f117-4b86-8cbc-fd8500f829db', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a86a598d-f117-4b86-8cbc-fd8500f829db', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7442e6d9-b040-4cc3-a601-2e27ba36cb13', $q$In-Context Editing$q$, $q$Content editors can modify text, images, and layout directly on the live page instead of through a separate admin interface.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7442e6d9-b040-4cc3-a601-2e27ba36cb13', $q$Page Version History$q$, $q$Every page revision is tracked, wiki-style, allowing content to be reviewed and rolled back.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7442e6d9-b040-4cc3-a601-2e27ba36cb13', $q$Fine-Grained Permissions$q$, $q$A role-based permissions system supports complex organizational approval and editing workflows.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7442e6d9-b040-4cc3-a601-2e27ba36cb13', $q$MVC Architecture & Developer API$q$, $q$Developers can extend and customize the platform through a documented API and standard MVC structure.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7442e6d9-b040-4cc3-a601-2e27ba36cb13', $q$Built-In SEO Tooling$q$, $q$Native search-engine-optimization features are included without requiring third-party plugins.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7442e6d9-b040-4cc3-a601-2e27ba36cb13', $q$Multisite Support$q$, $q$Version 9 introduced the ability to manage multiple sites from a single Concrete CMS installation.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7442e6d9-b040-4cc3-a601-2e27ba36cb13', $q$Marketplace of Themes & Add-Ons$q$, $q$A marketplace offers additional free and paid themes and functionality extensions.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7442e6d9-b040-4cc3-a601-2e27ba36cb13', $q$Free and open source under the permissive MIT license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7442e6d9-b040-4cc3-a601-2e27ba36cb13', $q$Strong built-in permissions and page version history without extra plugins$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7442e6d9-b040-4cc3-a601-2e27ba36cb13', $q$In-context editing is approachable for non-technical content editors$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7442e6d9-b040-4cc3-a601-2e27ba36cb13', $q$Active marketplace and optional managed hosting for teams that want it$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7442e6d9-b040-4cc3-a601-2e27ba36cb13', $q$Smaller plugin, theme, and developer ecosystem than WordPress$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7442e6d9-b040-4cc3-a601-2e27ba36cb13', $q$Managed hosting adds recurring cost beyond the free open-source core$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7442e6d9-b040-4cc3-a601-2e27ba36cb13', $q$Sites still on the legacy 5.x (concrete5) branch require migration to stay supported$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7442e6d9-b040-4cc3-a601-2e27ba36cb13', $q$Fewer third-party integrations available compared to larger CMS platforms$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7442e6d9-b040-4cc3-a601-2e27ba36cb13', $q$Is Concrete CMS free?$q$, $q$Yes, the core software is free and open source under the MIT license. Optional managed hosting from PortlandLabs is a paid service starting around $4.99/month.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7442e6d9-b040-4cc3-a601-2e27ba36cb13', $q$Is Concrete CMS the same as concrete5?$q$, $q$Yes. concrete5 was officially rebranded to Concrete CMS in July 2021, alongside the version 9 release.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7442e6d9-b040-4cc3-a601-2e27ba36cb13', $q$Who maintains Concrete CMS?$q$, $q$PortlandLabs Inc., a company based in Portland, Oregon, that has maintained the project since its early concrete5 days.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7442e6d9-b040-4cc3-a601-2e27ba36cb13', $q$What's new in Concrete CMS 9?$q$, $q$Multisite support, a boards feature, a gallery block, and a UI rebuilt on Bootstrap 5, released in October 2021.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7442e6d9-b040-4cc3-a601-2e27ba36cb13', $q$Can I self-host Concrete CMS?$q$, $q$Yes, it can be downloaded and self-hosted for free under the MIT license, or run on PortlandLabs' managed hosting plans.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7442e6d9-b040-4cc3-a601-2e27ba36cb13', $q$Government and Institutional Websites$q$, $q$Organizations needing granular, role-based editorial permissions use Concrete CMS's built-in access controls.$q$, $q$Public sector and institutional web teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7442e6d9-b040-4cc3-a601-2e27ba36cb13', $q$Small Business and Agency Sites$q$, $q$In-context editing lets non-technical staff update site content without training on a separate admin panel.$q$, $q$Marketing teams and web agencies$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7442e6d9-b040-4cc3-a601-2e27ba36cb13', $q$Open Source (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["MIT license","Unlimited use","Community support","Access to marketplace add-ons"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7442e6d9-b040-4cc3-a601-2e27ba36cb13', $q$Starter Hosting$q$, $q$$4.99/month$q$, $q$Monthly$q$, NULL, $q$["Managed hosting","Core CMS pre-installed","Basic support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7442e6d9-b040-4cc3-a601-2e27ba36cb13', $q$Business Hosting$q$, $q$$19/month$q$, $q$Monthly$q$, NULL, $q$["Managed hosting","More resources than Starter","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7442e6d9-b040-4cc3-a601-2e27ba36cb13', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Concrete CMS traces its roots to 2003, when its core toolkit was built for LewisAndClark200.org, the Ad Council's official Lewis & Clark Bicentennial site. That toolkit grew into the open-source CMS long known as concrete5, maintained by PortlandLabs Inc. of Portland, Oregon, and formally rebranded to Concrete CMS in July 2021 alongside the version 9 release.$q$, $q$The software is free and open source under the MIT license, with more than 62,000 reported live sites as of 2021. Its hallmark is in-context editing — content is edited directly on the live page rather than in a separate admin panel — paired with page-level version history and a fine-grained, role-based permissions system.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7442e6d9-b040-4cc3-a601-2e27ba36cb13', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Concrete CMS is built on an MVC architecture with a documented developer API, integrated server-side caching, and a built-in image editor. Version 9 (October 2021) added multisite management, a boards feature, and a gallery block, all running on a Bootstrap 5-based UI; the current stable release is 9.4.2 (July 2025).$q$, $q$A marketplace of themes and add-ons extends the core platform, and native SEO tooling is built in rather than bolted on through third-party plugins, which is one reason the CMS has historically found traction with government and institutional sites that need granular editorial permissions out of the box.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7442e6d9-b040-4cc3-a601-2e27ba36cb13', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The Concrete CMS software itself is free under the MIT license with no cost to download, install, or modify. Organizations that self-host only pay for their own server infrastructure.$q$, $q$For teams that don't want to manage hosting themselves, PortlandLabs offers managed hosting plans through concretecms.com, with published starting prices around $4.99/month for an entry-level Starter tier and roughly $19/month for a Business tier that includes more resources and support.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7442e6d9-b040-4cc3-a601-2e27ba36cb13', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7442e6d9-b040-4cc3-a601-2e27ba36cb13', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7442e6d9-b040-4cc3-a601-2e27ba36cb13', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7442e6d9-b040-4cc3-a601-2e27ba36cb13', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7442e6d9-b040-4cc3-a601-2e27ba36cb13', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7442e6d9-b040-4cc3-a601-2e27ba36cb13', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7442e6d9-b040-4cc3-a601-2e27ba36cb13', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e84117d-d544-4f29-89e5-dcf3d6e9f06a', $q$Single Binary Deployment$q$, $q$Conduit ships as one binary with no separate application server components to install.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e84117d-d544-4f29-89e5-dcf3d6e9f06a', $q$Embedded Database$q$, $q$Uses an embedded database (RocksDB by default) instead of requiring a separately managed PostgreSQL instance.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e84117d-d544-4f29-89e5-dcf3d6e9f06a', $q$Low Resource Requirements$q$, $q$Designed to run on modest hardware, including devices as small as a Raspberry Pi.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e84117d-d544-4f29-89e5-dcf3d6e9f06a', $q$Matrix Protocol Federation$q$, $q$Communicates with any other Matrix-compliant homeserver and can bridge to platforms like Discord.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e84117d-d544-4f29-89e5-dcf3d6e9f06a', $q$Rust-Based Implementation$q$, $q$Built in Rust for memory safety and performance relative to Python-based Synapse.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5e84117d-d544-4f29-89e5-dcf3d6e9f06a', $q$Open Source & Self-Hosted$q$, $q$Fully open source under Apache 2.0, giving operators complete control over their own chat server.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5e84117d-d544-4f29-89e5-dcf3d6e9f06a', $q$Much simpler setup than Synapse, with no external database to manage$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5e84117d-d544-4f29-89e5-dcf3d6e9f06a', $q$Efficient enough to run on low-cost, low-resource hardware$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5e84117d-d544-4f29-89e5-dcf3d6e9f06a', $q$Free and open source with no vendor or subscription$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5e84117d-d544-4f29-89e5-dcf3d6e9f06a', $q$Full Matrix federation compatibility with other homeservers and bridges$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5e84117d-d544-4f29-89e5-dcf3d6e9f06a', $q$Labeled beta and missing some smaller features found in Synapse$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5e84117d-d544-4f29-89e5-dcf3d6e9f06a', $q$Smaller plugin/module ecosystem than more mature homeservers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5e84117d-d544-4f29-89e5-dcf3d6e9f06a', $q$Development has partly moved into community forks (Conduwuit, Tuwunel), which can create confusion about which project to use$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5e84117d-d544-4f29-89e5-dcf3d6e9f06a', $q$Requires technical comfort with self-hosting and server administration$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5e84117d-d544-4f29-89e5-dcf3d6e9f06a', $q$Is Conduit free?$q$, $q$Yes, Conduit is free and open source under the Apache 2.0 license; you only pay for the server it runs on.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5e84117d-d544-4f29-89e5-dcf3d6e9f06a', $q$What is Conduit built with?$q$, $q$It's written in Rust and uses an embedded database (RocksDB by default) instead of a separate database server.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5e84117d-d544-4f29-89e5-dcf3d6e9f06a', $q$Who maintains Conduit?$q$, $q$It was created by Timo Kösters, with support from Famedly, a Berlin-based secure-messaging company.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5e84117d-d544-4f29-89e5-dcf3d6e9f06a', $q$Is Conduit production-ready?$q$, $q$The project describes itself as beta — usable today but still missing some smaller features found in more mature homeservers like Synapse.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5e84117d-d544-4f29-89e5-dcf3d6e9f06a', $q$What is the difference between Conduit, Conduwuit, and Tuwunel?$q$, $q$Conduwuit is a community hard fork of Conduit that added features at a faster pace, and Tuwunel is described as its official successor.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5e84117d-d544-4f29-89e5-dcf3d6e9f06a', $q$Self-Hosted Personal or Family Chat Server$q$, $q$Privacy-focused individuals run their own Matrix homeserver instead of relying on a third-party chat provider.$q$, $q$Privacy-conscious individuals and hobbyists$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5e84117d-d544-4f29-89e5-dcf3d6e9f06a', $q$Lightweight Community Server on Low-Cost Hardware$q$, $q$Small communities and organizations self-host federated chat on inexpensive infrastructure like a Raspberry Pi or small VPS.$q$, $q$Small organizations, communities, and sysadmins$q$, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5e84117d-d544-4f29-89e5-dcf3d6e9f06a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Conduit is a free, open-source Matrix homeserver written in Rust, started by developer Timo Kösters in February 2020 with support from the Berlin-based secure-messaging company Famedly. It later received six months of funding from Germany's Federal Ministry of Education and Research (BMBF) to support its development as open digital infrastructure.$q$, $q$The project's core goal is simplicity: it ships as a single binary with an embedded database rather than requiring a separately managed database server, making it noticeably lighter to set up and run than Synapse, the reference Matrix homeserver implementation.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5e84117d-d544-4f29-89e5-dcf3d6e9f06a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Conduit implements the Matrix federation protocol, so a self-hosted instance can communicate with users on any other compliant Matrix homeserver, and can bridge to external chat platforms like Discord through standard Matrix bridges. Being written in Rust, it aims for strong performance and memory safety with low resource requirements, explicitly targeting hardware as modest as a Raspberry Pi.$q$, $q$The project is licensed under Apache 2.0 and hosted on GitLab under the Famedly namespace. Its most active fork, 'Conduwuit,' added features and fixes at a faster pace and has since been succeeded by a project called 'Tuwunel,' so researchers evaluating Conduit today should check which codebase is most actively maintained for their needs.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5e84117d-d544-4f29-89e5-dcf3d6e9f06a', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Conduit is entirely free and open source with no commercial tier, subscription, or vendor behind it as a product. There is no cost to download, modify, or run it.$q$, $q$The only expense involved is the infrastructure an individual or organization chooses to run it on, which — thanks to its low resource footprint — can be inexpensive compared to hosting a full Synapse deployment.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5e84117d-d544-4f29-89e5-dcf3d6e9f06a', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5e84117d-d544-4f29-89e5-dcf3d6e9f06a', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5e84117d-d544-4f29-89e5-dcf3d6e9f06a', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cce6651b-abc7-4428-9917-f07ac8142bf2', $q$Feature Flags & Targeting Rules$q$, $q$Toggle features and target specific user segments with rule-based conditions.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cce6651b-abc7-4428-9917-f07ac8142bf2', $q$Flat-Tier, Usage-Based Pricing$q$, $q$Unlimited seats and monthly active users on every plan; pricing scales by config-download volume instead.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cce6651b-abc7-4428-9917-f07ac8142bf2', $q$Open-Source SDKs$q$, $q$SDKs for JavaScript, Python, Go, Java, .NET, iOS, Android, Node.js, and more, all open source.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cce6651b-abc7-4428-9917-f07ac8142bf2', $q$Percentage-Based Rollouts & Segments$q$, $q$Gradually roll out features to a percentage of users or defined audience segments.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cce6651b-abc7-4428-9917-f07ac8142bf2', $q$Audit Logs$q$, $q$Track configuration and flag changes with retention windows that scale by plan.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cce6651b-abc7-4428-9917-f07ac8142bf2', $q$Webhooks & REST API$q$, $q$Automate workflows and integrate flag changes into CI/CD or other internal systems.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cce6651b-abc7-4428-9917-f07ac8142bf2', $q$SOC 2 Type II Compliance$q$, $q$Independently audited security controls suitable for enterprise procurement requirements.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cce6651b-abc7-4428-9917-f07ac8142bf2', $q$Predictable flat pricing regardless of team size or end-user volume$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cce6651b-abc7-4428-9917-f07ac8142bf2', $q$Generous free tier with no credit card required$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cce6651b-abc7-4428-9917-f07ac8142bf2', $q$Open-source SDKs across a wide range of languages and platforms$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cce6651b-abc7-4428-9917-f07ac8142bf2', $q$SOC 2 Type II certified$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cce6651b-abc7-4428-9917-f07ac8142bf2', $q$Fewer advanced experimentation/analytics features than dedicated A/B testing platforms$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cce6651b-abc7-4428-9917-f07ac8142bf2', $q$Smaller company and ecosystem than category leader LaunchDarkly$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cce6651b-abc7-4428-9917-f07ac8142bf2', $q$Higher tiers can get expensive for applications with very high config-download volume$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cce6651b-abc7-4428-9917-f07ac8142bf2', $q$Audit log retention is limited on lower tiers (7-35 days) versus 2 years on Enterprise/Dedicated$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cce6651b-abc7-4428-9917-f07ac8142bf2', $q$Is ConfigCat free?$q$, $q$Yes, a Forever Free plan covers up to 10 feature flags and 5 million config downloads per month with no credit card required.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cce6651b-abc7-4428-9917-f07ac8142bf2', $q$How is ConfigCat priced?$q$, $q$By CDN configuration-download volume and network traffic rather than by seats or monthly active users — every plan includes unlimited team members and end users.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cce6651b-abc7-4428-9917-f07ac8142bf2', $q$Who founded ConfigCat?$q$, $q$Zoltán, Gergely Sinka, and Lajos Szőke founded ConfigCat in Budapest, Hungary, in 2018.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cce6651b-abc7-4428-9917-f07ac8142bf2', $q$Is ConfigCat SOC 2 compliant?$q$, $q$Yes, it holds SOC 2 Type II certification.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cce6651b-abc7-4428-9917-f07ac8142bf2', $q$What languages does ConfigCat support via SDK?$q$, $q$JavaScript, Python, Go, Java, .NET, iOS, Android, and Node.js, among other platforms, all through open-source SDKs.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cce6651b-abc7-4428-9917-f07ac8142bf2', $q$Progressive Feature Rollouts$q$, $q$Engineering teams gradually release new functionality to a percentage of users or specific segments to limit blast radius.$q$, $q$Software engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cce6651b-abc7-4428-9917-f07ac8142bf2', $q$Remote Configuration & Kill Switches$q$, $q$Teams change application behavior or disable risky features instantly without a full redeploy.$q$, $q$Product and DevOps teams$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cce6651b-abc7-4428-9917-f07ac8142bf2', $q$Forever Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["10 feature flags","2 environments, 2 products","5 million config downloads/month","20GB network traffic/month","7-day audit log retention"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cce6651b-abc7-4428-9917-f07ac8142bf2', $q$Pro$q$, $q$$110/month$q$, $q$Monthly$q$, NULL, $q$["100 feature flags","3 environments, 3 products","25 million downloads/month","100GB traffic/month","35-day audit log retention"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cce6651b-abc7-4428-9917-f07ac8142bf2', $q$Smart$q$, $q$$325/month$q$, $q$Monthly$q$, NULL, $q$["Unlimited feature flags, environments, up to 10 products","250 million downloads/month","1TB traffic/month","35-day audit log retention"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cce6651b-abc7-4428-9917-f07ac8142bf2', $q$Enterprise$q$, $q$$900/month$q$, $q$Monthly$q$, NULL, $q$["Unlimited resources","1 billion downloads/month","4TB traffic/month","2-year audit log retention","Premium SLA support"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cce6651b-abc7-4428-9917-f07ac8142bf2', $q$Dedicated$q$, $q$$4,500/month$q$, $q$Monthly$q$, NULL, $q$["6+ billion downloads/month","24TB traffic/month","Private cloud deployment options","Premium SLA support"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cce6651b-abc7-4428-9917-f07ac8142bf2', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$ConfigCat is a Budapest, Hungary-based feature flag and remote configuration platform founded in 2018 by Zoltán, Gergely Sinka, and Lajos Szőke. The company was bootstrapped without venture funding, struggled through a slow first year, and grew largely through word of mouth after being listed as a LaunchDarkly alternative on AlternativeTo.net, eventually landing customers including Microsoft and H&M.$q$, $q$The platform lets engineering teams toggle features, run controlled rollouts, and manage remote configuration values without redeploying an application, and it holds SOC 2 Type II certification.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cce6651b-abc7-4428-9917-f07ac8142bf2', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$ConfigCat supports feature flags, percentage-based rollouts, audience segments, targeting rules, webhooks, and audit logs, all accessible through a dashboard or REST API. Its SDKs — covering JavaScript, Python, Go, Java, .NET, iOS, Android, and Node.js, among others — are open source.$q$, $q$The platform's defining feature is its pricing structure: unlike most feature flag competitors, ConfigCat does not charge per seat or per monthly active user, instead billing based on CDN configuration-download volume and network traffic, with unlimited team members and end users on every plan.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cce6651b-abc7-4428-9917-f07ac8142bf2', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$ConfigCat offers a Forever Free plan (10 feature flags, 5 million downloads per month, no card required) plus four paid tiers: Pro at $110/month, Smart at $325/month, Enterprise at $900/month, and Dedicated at $4,500/month, each scaling primarily by config-download volume, network traffic, and audit-log retention rather than by team size.$q$, $q$All plans, including the free tier, include unlimited seats, unlimited monthly active users, and API access, which differentiates ConfigCat's pricing model from per-seat competitors like LaunchDarkly.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cce6651b-abc7-4428-9917-f07ac8142bf2', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cce6651b-abc7-4428-9917-f07ac8142bf2', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
