INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('39e56d84-4a54-4701-a19c-201f229ce404', $q$Pages, Spaces & Whiteboards$q$, $q$Content is organized into spaces and pages, with whiteboards available for visual collaboration.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('39e56d84-4a54-4701-a19c-201f229ce404', $q$Real-Time Collaborative Editing$q$, $q$Multiple team members can edit the same page simultaneously.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('39e56d84-4a54-4701-a19c-201f229ce404', $q$Templates Library$q$, $q$A large set of templates covers use cases like product requirements, meeting notes, and retrospectives.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('39e56d84-4a54-4701-a19c-201f229ce404', $q$Jira Integration$q$, $q$Pages and issues link natively, since Confluence and Jira share the same Atlassian platform.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('39e56d84-4a54-4701-a19c-201f229ce404', $q$Rovo AI$q$, $q$AI-powered search, summarization, and content generation bundled into Standard and higher plans.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('39e56d84-4a54-4701-a19c-201f229ce404', $q$Granular Permissions & Guest Access$q$, $q$Fine-grained space and page-level permissions, including external guest access on paid plans.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('39e56d84-4a54-4701-a19c-201f229ce404', $q$Automation Rules$q$, $q$No-code automation for repetitive actions like notifications and page updates.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('39e56d84-4a54-4701-a19c-201f229ce404', $q$Confluence Data Center$q$, $q$A clustered, self-hosted deployment option for organizations that can't use the cloud SaaS product.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('39e56d84-4a54-4701-a19c-201f229ce404', $q$Deep integration with Jira and the rest of the Atlassian ecosystem$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('39e56d84-4a54-4701-a19c-201f229ce404', $q$Mature permissions model and large template library$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('39e56d84-4a54-4701-a19c-201f229ce404', $q$Both cloud (SaaS) and self-hosted (Data Center) deployment options$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('39e56d84-4a54-4701-a19c-201f229ce404', $q$Free plan available for very small teams$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('39e56d84-4a54-4701-a19c-201f229ce404', $q$Per-user pricing scales quickly for larger teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('39e56d84-4a54-4701-a19c-201f229ce404', $q$Confluence Data Center licensing is expensive relative to the discontinued Server option$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('39e56d84-4a54-4701-a19c-201f229ce404', $q$Page/space structure has a learning curve for non-technical users$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('39e56d84-4a54-4701-a19c-201f229ce404', $q$Rovo AI features are gated behind paid plans$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('39e56d84-4a54-4701-a19c-201f229ce404', $q$Is Confluence free?$q$, $q$Yes, a Free plan supports up to 10 users with basic pages, spaces, and 2GB of storage.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('39e56d84-4a54-4701-a19c-201f229ce404', $q$What's the difference between Confluence Cloud and Data Center?$q$, $q$Cloud is Atlassian's hosted SaaS product; Data Center is a self-hosted, clustered option licensed per user tier for organizations that need on-premises control.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('39e56d84-4a54-4701-a19c-201f229ce404', $q$Does Confluence integrate with Jira?$q$, $q$Yes, both products share Atlassian's platform, and pages can be linked directly to Jira issues.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('39e56d84-4a54-4701-a19c-201f229ce404', $q$When was Confluence released?$q$, $q$Confluence 1.0 launched on March 25, 2004, two years after Atlassian's first product, Jira.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('39e56d84-4a54-4701-a19c-201f229ce404', $q$Does Confluence include AI features?$q$, $q$Yes, Rovo AI is bundled starting on the Standard plan, offering search, summarization, and content generation.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('39e56d84-4a54-4701-a19c-201f229ce404', $q$Can I still buy a Confluence Server license?$q$, $q$No, Atlassian has discontinued Server licensing; current self-hosted customers use Confluence Data Center instead.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('39e56d84-4a54-4701-a19c-201f229ce404', $q$Engineering Documentation & Knowledge Bases$q$, $q$Software teams that already use Jira document architecture, processes, and requirements in linked Confluence pages.$q$, $q$Software engineering and product teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('39e56d84-4a54-4701-a19c-201f229ce404', $q$Company-Wide Intranet & Meeting Notes$q$, $q$Non-technical departments use Confluence spaces for policies, onboarding, and meeting documentation.$q$, $q$HR, marketing, and operations teams$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('39e56d84-4a54-4701-a19c-201f229ce404', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Up to 10 users","2GB storage","Basic pages and spaces","10 automation rule runs/month"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('39e56d84-4a54-4701-a19c-201f229ce404', $q$Standard$q$, $q$$5.42/user/month$q$, $q$Annual$q$, NULL, $q$["Up to 150,000 users","250GB storage","Rovo AI","Guest access","Advanced permissions","100 automation runs/month"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('39e56d84-4a54-4701-a19c-201f229ce404', $q$Premium$q$, $q$$10.44/user/month$q$, $q$Annual$q$, NULL, $q$["Expanded storage and automation","Admin insights","Premium support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('39e56d84-4a54-4701-a19c-201f229ce404', $q$Enterprise$q$, $q$Custom$q$, $q$Annual$q$, NULL, $q$["Custom contract terms","Enterprise-grade security and governance"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('39e56d84-4a54-4701-a19c-201f229ce404', $q$Data Center (Self-Hosted)$q$, $q$From ~$28,000/year (500 users)$q$, $q$Annual$q$, NULL, $q$["Self-hosted deployment","Clustering and high availability"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('39e56d84-4a54-4701-a19c-201f229ce404', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Confluence is Atlassian's team workspace and enterprise wiki product, first released as Confluence 1.0 on March 25, 2004, two years after Atlassian's founding and the launch of its first product, Jira. Atlassian was founded in Sydney, Australia, in 2002 by Mike Cannon-Brookes and Scott Farquhar.$q$, $q$Confluence organizes content into spaces and pages, supports real-time collaborative editing and whiteboards, and offers a large template library for use cases such as product requirements, meeting notes, and internal documentation, with native integration into Jira and the rest of Atlassian's product suite.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('39e56d84-4a54-4701-a19c-201f229ce404', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Confluence Data Center, released in 2014, added clustering and high availability for large self-hosted deployments, and remains the self-hosted option today after Atlassian discontinued its Server license. More recently, Atlassian has integrated Rovo AI into Confluence for semantic search, summarization, and content generation on paid plans.$q$, $q$Permissions and guest access allow fine-grained control over who can view or edit specific spaces and pages, while automation rules let teams trigger actions (like notifications or page updates) without manual work.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('39e56d84-4a54-4701-a19c-201f229ce404', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Confluence Cloud offers a Free plan for up to 10 users, a Standard plan at $5.42 per user per month (billed annually), a Premium plan at $10.44 per user per month (billed annually), and custom-priced Enterprise plans available only on annual contracts.$q$, $q$Organizations that need to self-host can use Confluence Data Center, which is licensed per user tier and estimated at roughly $28,000 per year for a 500-user deployment, since Atlassian no longer sells the older, cheaper Server license.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('39e56d84-4a54-4701-a19c-201f229ce404', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('39e56d84-4a54-4701-a19c-201f229ce404', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
