INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0b888188-3d57-4941-b06a-2c4600263666', $q$Policy-as-Code (MAML)$q$, $q$A YAML-based language for declaring machines, users, and their access privileges as version-controlled policy.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0b888188-3d57-4941-b06a-2c4600263666', $q$REST API for Secrets & Identity$q$, $q$Programmatic access for storing secrets, managing identity lifecycles, and authorizing resource access.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0b888188-3d57-4941-b06a-2c4600263666', $q$Built-In Authenticators & Rotators$q$, $q$Supports automatic, dynamic credential rotation instead of relying on static, long-lived secrets.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0b888188-3d57-4941-b06a-2c4600263666', $q$AES-256-GCM Encryption$q$, $q$Secrets are encrypted at rest using CyberArk's Slosilo cryptography library.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0b888188-3d57-4941-b06a-2c4600263666', $q$Multi-Tenant Account Support$q$, $q$Multiple isolated environments can be managed from a single Conjur deployment.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0b888188-3d57-4941-b06a-2c4600263666', $q$DevOps Toolchain Integrations$q$, $q$Native integrations with Kubernetes, Docker, Ansible, Chef, Puppet, Terraform, and Jenkins.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0b888188-3d57-4941-b06a-2c4600263666', $q$Role-Based Access Policies$q$, $q$Fine-grained, role-based control over which identities can access which secrets.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0b888188-3d57-4941-b06a-2c4600263666', $q$Free, open-source core with an enterprise-grade security model$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0b888188-3d57-4941-b06a-2c4600263666', $q$Strong policy-as-code approach to machine identity and access control$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0b888188-3d57-4941-b06a-2c4600263666', $q$Deep integrations across common DevOps and cloud toolchains$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0b888188-3d57-4941-b06a-2c4600263666', $q$Backed by CyberArk's established security expertise$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0b888188-3d57-4941-b06a-2c4600263666', $q$Steeper learning curve (Ruby-based, MAML policy language) than simpler tools like HashiCorp Vault or Doppler$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0b888188-3d57-4941-b06a-2c4600263666', $q$Open-source edition lacks the high-availability clustering and disaster recovery in the commercial tier$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0b888188-3d57-4941-b06a-2c4600263666', $q$Smaller open-source community (under 1,000 GitHub stars) than competing secrets managers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0b888188-3d57-4941-b06a-2c4600263666', $q$Commercial pricing is quote-based and enterprise-oriented, less accessible to small teams$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0b888188-3d57-4941-b06a-2c4600263666', $q$Is Conjur free?$q$, $q$Yes, Conjur Open Source is free and self-hosted under LGPL v3.0/Apache 2.0 licenses.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0b888188-3d57-4941-b06a-2c4600263666', $q$Who owns Conjur?$q$, $q$CyberArk, which was acquired by Palo Alto Networks in a deal that completed in February 2026.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0b888188-3d57-4941-b06a-2c4600263666', $q$What's the difference between Conjur Open Source and CyberArk Secrets Manager?$q$, $q$The commercial tier adds high-availability clustering, disaster recovery, vendor support, and certified integrations on top of the free, open-source engine.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0b888188-3d57-4941-b06a-2c4600263666', $q$What language is Conjur written in?$q$, $q$Primarily Ruby, with a YAML-based policy language called MAML for access control.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0b888188-3d57-4941-b06a-2c4600263666', $q$Does Conjur integrate with Kubernetes?$q$, $q$Yes, along with Docker, Ansible, Chef, Puppet, Terraform, Jenkins, and major cloud platforms.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0b888188-3d57-4941-b06a-2c4600263666', $q$Machine Identity & Secrets Management for DevOps Pipelines$q$, $q$Platform and security teams use Conjur to secure credentials used by CI/CD tools and automated deployments.$q$, $q$Platform and security engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0b888188-3d57-4941-b06a-2c4600263666', $q$Centralized Secrets Inside a PAM Program$q$, $q$Large enterprises embed Conjur's policy-driven access model into a broader privileged access management strategy.$q$, $q$Large enterprises with dedicated security teams$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0b888188-3d57-4941-b06a-2c4600263666', $q$Conjur Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["LGPL v3.0/Apache 2.0 license","Self-hosted","Policy-as-code access control","Community support via CyberArk Commons"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0b888188-3d57-4941-b06a-2c4600263666', $q$CyberArk Secrets Manager (Commercial)$q$, $q$Custom$q$, $q$Annual/Custom$q$, NULL, $q$["High-availability clustering","Disaster recovery","Certified integrations","Vendor support"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0b888188-3d57-4941-b06a-2c4600263666', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Conjur is an open-source secrets management and machine-identity platform acquired by security vendor CyberArk in 2017 and open-sourced later that same year. It provides a policy-based access model, built around a YAML-based language called MAML, for securing secrets and non-human identities used by DevOps pipelines and cloud-native applications.$q$, $q$The server is licensed under LGPL v3.0, with API clients under Apache 2.0, and the codebase is written primarily in Ruby. CyberArk was itself acquired by Palo Alto Networks in a roughly $25 billion deal that closed in February 2026, placing Conjur within a much larger security portfolio.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0b888188-3d57-4941-b06a-2c4600263666', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Conjur exposes a REST API for secret storage, retrieval, and identity lifecycle management, with built-in authenticators and rotators that support automatic credential rotation instead of static secrets. Secrets are encrypted with AES-256-GCM via CyberArk's Slosilo library, and multi-tenant account support allows multiple isolated environments in one deployment.$q$, $q$It integrates with major DevOps toolchains — Kubernetes, Docker, Ansible, Chef, Puppet, Terraform, and Jenkins — as well as leading cloud infrastructure platforms, positioning it as infrastructure for machine-to-machine authentication at scale rather than a simple key-value secrets store.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0b888188-3d57-4941-b06a-2c4600263666', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Conjur Open Source is free to download, self-host, and modify under its LGPL v3.0/Apache 2.0 licensing, with community support available through the CyberArk Commons Discourse forum.$q$, $q$CyberArk also sells a commercial product, now branded CyberArk Secrets Manager (formerly Conjur Enterprise), that adds high-availability clustering, disaster recovery, vendor support, and certified integrations on top of the open-source core. Pricing for this commercial tier is custom and quote-based rather than publicly listed.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0b888188-3d57-4941-b06a-2c4600263666', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0b888188-3d57-4941-b06a-2c4600263666', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0b888188-3d57-4941-b06a-2c4600263666', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$GPS Time Clock & Scheduling$q$, $q$Employees clock in and out with location tracking, and managers build and adjust shift schedules.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Task Management & Checklists$q$, $q$Digital forms, checklists, and task assignments replace paper-based processes.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Company-Wide Chat & Announcements$q$, $q$A news feed plus one-on-one and group chat keep deskless teams connected.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Time-Off & HR Document Management$q$, $q$Employees request time off and sign HR documents electronically.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Employee Training & Onboarding Courses$q$, $q$Build and assign training courses directly within the app.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Recognition & Rewards$q$, $q$Managers can recognize employees with badges and rewards.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Geofencing$q$, $q$Restrict clock-ins to defined job-site locations.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$API Access$q$, $q$Available on Expert-tier plans for integrating with other systems.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Free for life for businesses with up to 10 employees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Purpose-built for deskless and mobile-first workforces$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Modular hub pricing lets teams pay only for the features they need$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$14-day free trial with no credit card required$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Pricing across three separate hubs can add up if a team needs all of them$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Feature limits within each tier (like geofence site counts) require upgrades to remove$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Less depth in payroll and benefits administration than dedicated HR platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$API access and some advanced features are gated behind Expert or Enterprise tiers$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Is Connecteam free?$q$, $q$Yes, the Small Business Plan is free for life for businesses with up to 10 employees, including access to all three hubs.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Who founded Connecteam?$q$, $q$Hadar Shmueli and Amir Nehemia founded Connecteam in 2014.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$How is Connecteam priced?$q$, $q$Separately by hub (Operations, Communications, HR & Skills), each on Basic/Advanced/Expert/Enterprise tiers, with a flat rate for the first 30 users and a small per-additional-user fee beyond that.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Does Connecteam have a free trial?$q$, $q$Yes, a 14-day free trial with no credit card required is available on paid plans.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Is Connecteam available on mobile?$q$, $q$Yes, dedicated iOS and Android apps are built specifically for frontline, deskless employees.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Shift Scheduling and Time Tracking$q$, $q$Managers build schedules and track GPS-verified time for hourly employees.$q$, $q$Retail, construction, and hospitality managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Internal Communication & HR for Deskless Teams$q$, $q$HR and operations leads manage time off, onboarding, and company-wide announcements for employees without corporate email.$q$, $q$HR and operations leads at small-to-mid-size businesses$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Small Business Plan$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Up to 10 employees","Access to all three hubs"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Operations Hub - Basic$q$, $q$$29/month$q$, $q$Monthly (annual available)$q$, NULL, $q$["Up to 30 users","GPS time clock","Unlimited jobs/projects"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Operations Hub - Advanced$q$, $q$$49/month$q$, $q$Monthly (annual available)$q$, NULL, $q$["Auto clock-out","Up to 10 geofence sites","Advanced filters"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$Operations Hub - Expert$q$, $q$$99/month$q$, $q$Monthly (annual available)$q$, NULL, $q$["Unlimited geofence sites","Auto-assigned shifts","API access"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Connecteam is an all-in-one employee management app founded in 2014 by Hadar Shmueli and Amir Nehemia, headquartered in both New York City and Tel Aviv, Israel. It is built specifically for deskless, mobile-first workforces — retail, construction, hospitality, healthcare, and field service employees — rather than office workers with corporate email accounts.$q$, $q$The product is organized into three purchasable hubs: Operations (time tracking, scheduling, tasks), Communications (company chat and updates), and HR & Skills (time off, onboarding, training, recognition), which businesses can mix and match based on their needs.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The Operations Hub includes GPS-based time clocks, employee scheduling, task management, digital forms and checklists, and geofencing for job sites. The Communications Hub provides a company-wide news feed, one-on-one and group chat, scheduled updates, anonymous surveys, and an employee directory.$q$, $q$The HR & Skills Hub covers time-off requests and approvals, onboarding, e-signature document management, employee recognition and rewards, and training courses. Dedicated iOS and Android apps are designed around frontline, non-desk employees rather than a desktop-first workflow.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Businesses with up to 10 employees can use the Small Business Plan free for life, with access to all three hubs. Beyond that, each hub is sold separately on Basic, Advanced, Expert, or custom Enterprise tiers, priced as a flat rate covering the first 30 users (for example, Operations Hub Basic starts at $29/month) plus a small per-additional-user fee beyond 30 users.$q$, $q$Annual billing saves roughly 18% compared to monthly billing, and every paid plan includes a 14-day free trial with no credit card required.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4e050c32-d03f-48b8-8e78-e896adddf250', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
