INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$Pricing scales quickly as a contact list grows$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$Fewer advanced segmentation and automation options than competitors like ActiveCampaign$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$Templates and interface viewed by some reviewers as less modern than newer entrants$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$Does Constant Contact have a free plan?$q$, $q$No permanent free plan; it offers a free trial period before billing begins.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$How much does Constant Contact cost?$q$, $q$Plans start around $12/month (Lite) for 500 contacts, scaling up with plan tier (Standard $35/month, Premium $80/month) and contact list size.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$When was Constant Contact founded?$q$, $q$It was founded in 1995 as Roving Software and took the Constant Contact name in 2004.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$Does Constant Contact support SMS marketing?$q$, $q$Yes, text marketing is available alongside email campaigns.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$Who owns Constant Contact?$q$, $q$It currently operates under Clearlake Capital ownership, after previously being part of Endurance International Group, which acquired it in 2016.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$Email Newsletters and Promotions$q$, $q$Small business owners send regular newsletters and promotional campaigns to build customer relationships.$q$, $q$Small business owners and marketers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$Nonprofit Fundraising and Donor Communication$q$, $q$Nonprofits use automated and segmented campaigns to communicate with donors and supporters.$q$, $q$Nonprofit organizations$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$Lite$q$, $q$$12/month$q$, $q$Monthly (500 contacts)$q$, NULL, $q$["1 user","Core email sending","1 automation template"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$Standard$q$, $q$$35/month$q$, $q$Monthly (500 contacts)$q$, NULL, $q$["Up to 3 users","Full marketing automation","A/B testing","Social media scheduling"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$Premium$q$, $q$$80/month$q$, $q$Monthly (500 contacts)$q$, NULL, $q$["Unlimited users","Advanced automation","Google/Facebook ad management","SEO tools"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Constant Contact traces back to 1995, when it was founded as Roving Software by Randy Parker; it took the Constant Contact name in 2004 and went public in 2007, making it one of the longest-running email marketing platforms still in operation. The company is headquartered in Waltham, Massachusetts, with additional offices across the US, Australia, Canada, and the UK.$q$, $q$It is positioned primarily for small businesses and nonprofits that are new to digital marketing, prioritizing ease of use and customer support over deep technical customization, and now operates under Clearlake Capital ownership after being acquired by Endurance International Group in 2016.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core functionality includes a drag-and-drop email builder, AI-assisted content and subject-line generation, and marketing automation for common scenarios like welcome series, abandoned-cart reminders, re-engagement campaigns, and post-purchase follow-ups.$q$, $q$The platform also includes SMS/text marketing coordinated with email campaigns, landing pages and sign-up forms for lead capture, social media post scheduling, and, on higher tiers, Google and Facebook ad management alongside basic SEO tools.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d46e98c7-b182-4988-9c3a-b509b0e2beff', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Constant Contact's 2026 pricing has three tiers starting at a 500-contact base: Lite at $12/month, Standard at $35/month, and Premium at $80/month, each adding more users, automation, and marketing channels at higher tiers.$q$, $q$Pricing scales with contact list size rather than staying flat — for example, a 5,001-10,000 contact range costs roughly $120/month on Lite up to $275/month on Premium — and there is no permanent free plan, only a free trial period before billing begins.$q$]::text[], 2);
