-- Enrichment marathon batch: Concourse CI, Concrete CMS, Conduit, ConfigCat, Confluence, Conjur, Connecteam, Constant Contact

-- ── Concourse CI ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Concourse CI is a free, open-source, container-based automation system for CI/CD, built around declarative YAML pipelines, resources, and jobs.$q$, short_description),
  pricing_model = COALESCE($q$Free/Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Concourse CI: Open-Source CI/CD Pipeline Tool$q$, seo_title),
  seo_meta_description = COALESCE($q$Concourse CI is a free, open-source, container-based CI/CD automation tool with declarative YAML pipelines. Self-hosted, written in Go under Apache 2.0.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Concourse CI is a free, open-source, container-based automation system used primarily for continuous integration and continuous delivery (CI/CD). It was created in 2014 by Alex Suraci and Chris Brown, two engineers on the Pivotal Cloud Foundry team who grew frustrated with the plugin-heavy, click-configured nature of Jenkins while running Cloud Foundry's own build pipelines. The first commit dates to April 13, 2014, and the project was released as open source in 2015 with sponsorship from Pivotal. Concourse is licensed under Apache 2.0 and has no proprietary or paid edition; it must be self-hosted, as there is no official managed SaaS offering. The project is written mostly in Go (the web/ATC component) with Elm powering its browser UI, and as of mid-2026 its GitHub repository (concourse/concourse) has roughly 7,900 stars, with the latest release (v8.2.4) shipped in June 2026. Concourse is opinionated about a small set of principles: idempotency, immutability, declarative configuration, stateless workers, and reproducible builds. Rather than a UI built from checkboxes, pipelines are defined as a single declarative YAML file, functioning like what the project describes as 'a distributed, continuous Makefile.' Every pipeline is built from three primitives: resources (versioned external inputs/outputs such as Git repos or Docker images), tasks (units of work executed inside isolated containers), and jobs (sequences of tasks triggered by resource changes). Because every task runs in its own container with an explicitly specified image, builds are isolated and reproducible across machines. Concourse deliberately avoids a traditional plugin architecture; instead, integrations with external systems (Git, S3, Docker registries, Slack, and so on) are implemented as 'resource types' — ordinary container images conforming to a simple interface — so the core system stays small while still being extensible to virtually any tool. A companion CLI called fly lets developers execute a pipeline task locally with uncommitted changes before pushing, which shortens the debug loop compared to CI systems that only run on already-pushed code. The web dashboard renders pipelines as a graph so failures can be traced visually from a job back to its root task. Concourse can be deployed as a standalone binary, via Docker Compose for local development, through a Kubernetes Helm chart, or via a BOSH release for larger production deployments, with PostgreSQL as its backing datastore and separate web and worker nodes for scaling. The project has been supported over the years by organizations including the Cloud Foundry Foundation, Pix4D, SAP, and RamNode, and it maintains its own public pipelines at ci.concourse-ci.org as a real-world example of the tool in use. Concourse is best suited for engineering teams that want infrastructure-as-code style, git-versioned pipelines with strong reproducibility guarantees, and that are comfortable running and operating their own CI infrastructure rather than relying on a hosted SaaS CI product such as GitHub Actions or CircleCI.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'a86a598d-f117-4b86-8cbc-fd8500f829db';

