-- ── Concrete CMS ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Concrete CMS is a free, open-source content management system with in-context page editing, version history, and granular permissions, plus optional managed hosting.$q$, short_description),
  pricing_model = COALESCE($q$Freemium (free open-source core, paid managed hosting)$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted); managed hosting from $4.99/month$q$, starting_price),
  founded_year = COALESCE(2003, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Portland, Oregon, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Concrete CMS: Open-Source CMS Features & Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Concrete CMS is a free, open-source CMS with in-context editing and version history. Self-host under MIT license or use managed hosting from $4.99/month.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Concrete CMS is a free, open-source content management system originally developed in 2003 as part of building LewisAndClark200.org, the official site for the Ad Council's National Council for the Lewis & Clark Bicentennial. That project's underlying toolkit evolved into an open-source CMS eventually known as concrete5, maintained by PortlandLabs Inc., a Portland, Oregon-based company that began in 2002 as a full-service interactive media firm under founders Franz and Andy. On July 7, 2021, concrete5 was officially rebranded to Concrete CMS, dropping the version number from the name; the rebrand coincided with the release of version 9 in October 2021, which added multisite support, a boards feature, a new gallery block, and a UI rebuilt on Bootstrap 5. The software is licensed under the MIT license, making it free to download, modify, and self-host without restriction. As of 2021, Concrete CMS reported more than 62,000 live websites built on the platform. Its defining feature is in-context editing: users can edit page content, images, and layout directly on the live page rather than through a separate back-end interface, which lowers the technical bar for non-technical content editors. The platform also provides built-in version history for every page (similar to a wiki), a fine-grained, role-based permissions system suited to organizations with complex approval workflows, a model-view-controller (MVC) architecture for developers, an embedded image editor, integrated server-side caching, a documented developer API, and native SEO tooling. A marketplace offers additional themes and add-ons, both free and paid, for extending functionality. The legacy 5.x branch (concrete5) reached end of life in August 2019 with final release 5.6.4.0; the current line is version 9.x, with 9.4.2 released in July 2025 as the latest stable build. Beyond the free, self-hosted open-source core, PortlandLabs also operates concretecms.com, offering managed hosting plans that bundle infrastructure, updates, and support; pricing for these managed plans starts around $4.99/month for a Starter tier and roughly $19/month for a Business tier, according to third-party software review aggregators, though exact current pricing should be confirmed on Concrete CMS's own site since managed hosting pricing changes more frequently than the open-source license terms. Concrete CMS is positioned as an alternative to WordPress and Drupal for organizations — particularly government, educational, and enterprise sites — that need strong built-in permissions and page-level version control without heavy reliance on third-party plugins. It supports typical CMS use cases including corporate websites, intranets, and content-heavy institutional sites where multiple contributors with different access levels need to publish and revise pages independently.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '7442e6d9-b040-4cc3-a601-2e27ba36cb13';

