-- ── Conduit ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Conduit is a lightweight, open-source Matrix homeserver written in Rust, packaged as a single binary with an embedded database for easy self-hosting.$q$, short_description),
  pricing_model = COALESCE($q$Free/Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Berlin, Germany (Famedly, supporting sponsor)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Conduit: Lightweight Open-Source Matrix Homeserver$q$, seo_title),
  seo_meta_description = COALESCE($q$Conduit is a free, open-source Matrix homeserver written in Rust. It runs as a single binary with an embedded database, ideal for low-resource self-hosting.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Conduit is a lightweight, open-source homeserver implementation of the Matrix protocol, the open standard for secure, decentralized, federated real-time communication. The project was started by developer Timo Kösters, with its first commit made in February 2020, and has been supported by Famedly, a Berlin-based secure-messaging company that also works on Matrix-based products for regulated industries such as healthcare. In 2021, the project received six months of funding from the German Federal Ministry of Education and Research (BMBF), a public grant aimed at supporting open-source digital infrastructure. Conduit is written in Rust and distributed under the Apache 2.0 license, and its source lives on GitLab under the Famedly namespace, with a GitHub mirror also available. Its central design goal is simplicity: Conduit ships as a single binary with an embedded database (RocksDB by default), meaning operators do not need to separately install and manage PostgreSQL or another external database server, unlike Synapse, the original and most widely deployed Matrix homeserver written in Python by Matrix's core team. This makes Conduit substantially easier to set up and lighter on resources, with the project explicitly targeting hardware as modest as a Raspberry Pi. Functionally, Conduit implements the core Matrix specification needed to federate with other Matrix homeservers, meaning users on a self-hosted Conduit instance can communicate with users on Synapse, Dendrite, or any other compliant homeserver, as well as bridge to external platforms such as Discord via Matrix bridges. As of its most recent public documentation, the project describes itself as beta: usable in real deployments but still missing some smaller features relative to more mature homeservers. Notably, Conduit's development has partly diverged into community-driven forks. 'Conduwuit' emerged as a hard fork that added performance improvements and features at a faster pace than upstream Conduit, and it was later succeeded by a project called 'Tuwunel,' which describes itself as conduwuit's official successor. This means prospective self-hosters researching 'Conduit' today may also encounter these related but distinct projects, and should verify which codebase best matches their needs for feature completeness and active maintenance. Conduit itself carries no commercial pricing or company behind it as a product — it is purely open-source software that individuals or organizations run on their own infrastructure, so there is no subscription, seat pricing, or vendor lock-in, only the cost of the server it runs on. It is best suited for privacy-conscious individuals, small communities, and technically capable teams who want to operate their own sovereign, federated chat server without the operational overhead of running Synapse.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '5e84117d-d544-4f29-89e5-dcf3d6e9f06a';

