-- ── ConfigCat ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$ConfigCat is a feature flag and remote configuration platform with flat-tier pricing, unlimited seats and users, and open-source SDKs for 10+ platforms.$q$, short_description),
  pricing_model = COALESCE($q$Freemium/Flat-tier subscription$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE($q$~14 employees$q$, company_size),
  headquarters = COALESCE($q$Budapest, Hungary$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$ConfigCat: Feature Flags & Config Management Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$ConfigCat is a feature flag platform with flat-tier pricing, unlimited seats and MAUs, and open-source SDKs. Free plan available; paid plans from $110/month.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$ConfigCat is a feature flag and remote configuration management platform founded in 2018 in Budapest, Hungary, by three co-founders — Zoltán, Gergely Sinka, and Lajos Szőke — who bootstrapped the company without outside venture funding. According to the company's own account, the idea began when Zoltán, working as a product manager, kept running into a recurring problem around toggling and remotely configuring application behavior. He initially considered building a remote error-logging service but pivoted toward remote configuration and feature flags after finding fewer established competitors in that niche. The founders left their jobs to build ConfigCat full time and went through a difficult first year without paying customers before landing their first sale in 2019, a $200 purchase of the company's highest-tier plan. Early growth came largely through being listed on AlternativeTo.net as an alternative to LaunchDarkly, the market-leading feature flag platform, which helped ConfigCat attract larger customers including Microsoft and H&M; the company now reports an estimated 500-plus paying customers and holds SOC 2 Type II certification. ConfigCat's main differentiator versus competitors like LaunchDarkly and Split is its pricing model: rather than charging per seat or per monthly active user (MAU), which is standard among feature flag vendors, ConfigCat charges based on CDN configuration-download volume and network traffic, with unlimited seats, unlimited MAUs, and unlimited feature-flag reads included on every paid plan. As of the platform's published pricing, the tiers are: a Forever Free plan (10 feature flags, 2 environments, 2 products, 5 million config downloads per month, 20GB of network traffic, 7-day audit log retention, no credit card required); Pro at $110/month (100 feature flags, 3 environments and products, 25 million downloads per month, 100GB traffic, 35-day audit log retention); Smart at $325/month (unlimited feature flags, environments, segments and targeting rules across up to 10 products, 250 million downloads per month, 1TB traffic); Enterprise at $900/month (1 billion downloads per month, 4TB traffic, 2-year audit log retention, premium SLA support); and Dedicated at $4,500/month (6-billion-plus downloads per month, 24TB traffic, private cloud deployment options). ConfigCat provides open-source SDKs across a wide range of languages and platforms, including JavaScript, Python, Go, Java, .NET, iOS, Android, and Node.js, alongside a management dashboard, REST API, percentage-based rollouts, user segmentation, targeting rules, webhooks, and audit logging. It is used by engineering teams to progressively roll out features, run kill switches for risky changes, and manage remote configuration values without requiring a full application redeploy for every change.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'cce6651b-abc7-4428-9917-f07ac8142bf2';

