-- ── Confluence ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Confluence is Atlassian's team workspace and wiki for documentation, knowledge bases, and collaborative pages, tightly integrated with Jira.$q$, short_description),
  pricing_model = COALESCE($q$Freemium/Per-user subscription$q$, pricing_model),
  starting_price = COALESCE($q$Free (up to 10 users); paid plans from $5.42/user/month$q$, starting_price),
  founded_year = COALESCE(2004, founded_year),
  company_size = COALESCE($q$Atlassian: 10,000+ employees (public company)$q$, company_size),
  headquarters = COALESCE($q$Sydney, Australia (Atlassian)$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$, $q$German$q$, $q$Spanish$q$, $q$Japanese$q$]::text[],
  seo_title = COALESCE($q$Confluence: Atlassian Wiki Pricing, Features & FAQ$q$, seo_title),
  seo_meta_description = COALESCE($q$Confluence is Atlassian's team workspace for documentation and knowledge bases. Free for up to 10 users; paid plans start at $5.42/user/month.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Confluence is a team workspace and enterprise wiki product built by Atlassian, the Sydney, Australia-founded software company started in 2002 by Mike Cannon-Brookes and Scott Farquhar. Atlassian's first product was the issue-tracking tool Jira, released in 2002, and two years later, on March 25, 2004, Atlassian shipped Confluence 1.0 as an application built for enterprise knowledge management while retaining the simplicity of a wiki. At launch there was little direct competition for a purpose-built enterprise wiki, which helped Confluence establish itself as a default choice for software teams documenting alongside Jira. In 2014, Atlassian released Confluence Data Center, adding clustering and load-balanced high availability for large self-hosted deployments; Atlassian later phased out its traditional Server license entirely, pushing customers toward either Confluence Cloud (the SaaS product) or Confluence Data Center (self-hosted). More recently, Atlassian has integrated its Rovo AI features into Confluence for tasks like semantic search, page summarization, and content generation, bundled into paid plans. Functionally, Confluence organizes content into spaces and pages, supports real-time collaborative editing, whiteboards, and a large library of templates for use cases like product requirements, meeting notes, retrospectives, and internal knowledge bases, and integrates natively with Jira so issues and pages can be linked. As of 2026, Confluence Cloud pricing has four tiers: a Free plan supporting up to 10 users with 2GB of storage, basic pages and spaces, and 10 automation rule runs per month; a Standard plan at $5.42 per user per month (billed annually) supporting up to 150,000 users, 250GB of storage, Rovo AI, guest access, advanced permissions, and 100 automation runs per month with business-hours support; a Premium plan at $10.44 per user per month (billed annually) adding more automation capacity, expanded storage, and premium support; and a custom-priced Enterprise plan available only on annual contracts. For organizations that need to keep Confluence on their own infrastructure, Confluence Data Center is licensed per user tier, with published estimates putting the cost at roughly $28,000 per year for a 500-user deployment. Confluence is used broadly beyond software engineering — by HR, marketing, legal, and operations teams — as a central place to document processes, policies, and institutional knowledge, and its deep integration with the rest of Atlassian's suite (Jira, Trello, Loom, Bitbucket) is a primary reason organizations already using Atlassian tools adopt it as their default documentation platform rather than evaluating standalone wiki products.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '39e56d84-4a54-4701-a19c-201f229ce404';

