-- ── Conjur ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Conjur is CyberArk's open-source secrets management and machine-identity platform, providing policy-based access control and a REST API for DevOps.$q$, short_description),
  pricing_model = COALESCE($q$Free/Open Source (core); commercial tier via CyberArk Secrets Manager$q$, pricing_model),
  starting_price = COALESCE($q$Free (open source); commercial pricing is custom/quote-based$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Newton, Massachusetts, USA (CyberArk; now part of Palo Alto Networks)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Conjur: CyberArk's Open-Source Secrets Manager$q$, seo_title),
  seo_meta_description = COALESCE($q$Conjur is CyberArk's open-source secrets management platform with policy-based access control. Free and self-hosted, with a commercial enterprise tier.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Conjur is an open-source secrets management and machine-identity platform originally acquired by security vendor CyberArk in 2017, which then open-sourced the technology in September 2017 to give DevOps teams a free way to secure secrets and machine identities used by CI/CD pipelines and cloud-native applications. The Conjur server is licensed under GNU LGPL v3.0, while its API clients and extensions are licensed under Apache 2.0, and the codebase is written primarily in Ruby. Its core concept is a policy-as-code language called MAML (Machine Authorization Markup Language), a YAML-based format used to declare the machines, users, and privileges that make up an organization's access model. On top of this policy layer, Conjur exposes a REST API for storing and retrieving secrets, managing identity lifecycles, and authorizing resource access, and it includes built-in authenticators and rotators that support dynamic, automatic credential rotation rather than static, long-lived secrets. Secrets are encrypted using AES-256-GCM via CyberArk's Slosilo library, and the platform supports multi-tenant accounts so multiple isolated environments can be managed from one Conjur deployment. Conjur integrates with common DevOps toolchains including Kubernetes, Docker, Ansible, Chef, Puppet, Terraform, and Jenkins, as well as major cloud infrastructure platforms, which is central to its positioning as infrastructure for securing non-human, machine-to-machine authentication at scale. The open-source edition (Conjur OSS) remains actively maintained, with its GitHub repository (cyberark/conjur) showing roughly 941 stars, 147 forks, and a latest release of v1.27.0 in June 2026. CyberArk also sells a commercial product line, formerly branded 'Conjur Enterprise' and now marketed as CyberArk Secrets Manager, which builds on the open-source engine with high-availability clustering, disaster recovery, vendor support, and additional certified integrations — features not included in the free, self-hosted OSS edition. Ownership context matters for evaluating Conjur's long-term trajectory: CyberArk itself was acquired by Palo Alto Networks in a deal valued near $25 billion that completed in February 2026, meaning Conjur is now positioned within Palo Alto Networks' broader security portfolio rather than as a standalone company's flagship product. Support for the open-source edition is primarily community-driven through the CyberArk Commons Discourse forum rather than a vendor SLA. Conjur is best suited to large enterprises with dedicated security teams, significant compliance requirements, and large volumes of machine identities that need centralized, policy-driven access control, particularly organizations already invested in CyberArk's (now Palo Alto Networks') broader privileged access management (PAM) platform; smaller teams or those wanting a simpler setup often compare Conjur against alternatives like HashiCorp Vault.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '0b888188-3d57-4941-b06a-2c4600263666';

