-- ── Connecteam ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Connecteam is an all-in-one employee management app combining scheduling, GPS time tracking, task management, HR, and internal communication tools.$q$, short_description),
  pricing_model = COALESCE($q$Freemium/Per-user subscription$q$, pricing_model),
  starting_price = COALESCE($q$Free (up to 10 users); paid plans from $29/month$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$New York, USA and Tel Aviv, Israel$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Connecteam: Employee Management App Pricing & Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Connecteam is an all-in-one employee management app for deskless teams, covering scheduling, HR, and chat. Free for up to 10 users; paid plans from $29/month.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Connecteam is an all-in-one employee management app founded in 2014 by Hadar Shmueli and Amir Nehemia, with headquarters listed in both New York City and Tel Aviv, Israel. The product is built specifically for deskless, mobile-first workforces — employees in retail, construction, hospitality, healthcare, and field services who don't sit at a computer with a corporate email account — as an alternative to enterprise HR and workforce-management suites designed around office workers. Connecteam organizes its functionality into three separate 'hubs' that can be purchased independently: an Operations Hub covering GPS-based time clocks, employee scheduling, task management, digital forms and checklists, and geofencing; a Communications Hub covering a company-wide news feed, one-on-one and group chat, scheduled updates, anonymous surveys, and an employee directory; and an HR & Skills Hub covering time-off requests and approvals, employee onboarding, e-signature document management, recognition and reward programs, and training courses. Businesses with up to 10 employees can use a Small Business Plan that is free for life and includes access to all three hubs. Beyond that size, each hub is priced separately on a Basic, Advanced, Expert, or custom Enterprise tier, and pricing is structured as a flat monthly rate covering the first 30 users, with a small per-additional-user fee beyond that threshold — for example, the Operations Hub's Basic tier costs $29/month flat (or $35/month if billed monthly versus annually, with annual billing saving about 18%) for up to 30 users, then roughly $0.80 to $1.00 per additional user per month, while Advanced and Expert tiers cost $49 and $99/month respectively, with correspondingly higher per-user rates. The Communications and HR & Skills hubs follow the same Basic/Advanced/Expert/Enterprise structure at similar flat starting prices but lower per-additional-user costs. Every paid plan includes a 14-day free trial with no credit card required. Feature examples that gate tier upgrades include: on Operations, auto clock-out and expanded geofence site limits on Advanced, and unlimited geofence sites, auto-assigned shifts, and API access on Expert; on Communications, scheduled messages and anonymous surveys on Advanced, and API access with auto-translated updates on Expert; on HR & Skills, e-signature document limits that expand from Advanced to Expert, alongside unlimited training courses starting at Advanced. Connecteam offers dedicated iOS and Android mobile apps designed around frontline and non-desk employees rather than a desktop-first experience. It is positioned as a lower-cost, mobile-native alternative to larger enterprise HR platforms for small and mid-sized businesses that primarily manage hourly or shift-based workforces.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '4e050c32-d03f-48b8-8e78-e896adddf250';

