-- ── Constant Contact ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Constant Contact is an email and SMS marketing platform for small businesses, offering automation, landing pages, and AI-assisted content tools.$q$, short_description),
  pricing_model = COALESCE($q$Subscription (tiered by contact list size)$q$, pricing_model),
  starting_price = COALESCE($q$$12/month (Lite plan, 500 contacts)$q$, starting_price),
  founded_year = COALESCE(1995, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Waltham, Massachusetts, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Constant Contact: Email Marketing Pricing & Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Constant Contact is an email and SMS marketing platform for small businesses. Plans start at $12/month for 500 contacts, with automation and landing pages.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Constant Contact is an email and SMS marketing platform originally founded in 1995 as Roving Software by Randy Parker; the company adopted the Constant Contact name in 2004 and went public in 2007, making it one of the longest-running email marketing platforms still operating today. It was acquired by Endurance International Group (EIG) in 2016, and following a period under EIG's ownership of multiple web/marketing brands, it now operates under Clearlake Capital ownership. The company is headquartered in Waltham, Massachusetts, with additional US offices in Boston, Loveland (Colorado), Gainesville (Florida), and Los Angeles, plus international offices in Brisbane (Australia), Waterloo (Canada), and London (UK). Constant Contact is positioned primarily for small businesses and nonprofit organizations that are new to digital marketing, emphasizing ease of use and customer support over the deeper technical customization found in developer-oriented platforms. Core functionality includes a drag-and-drop email builder, AI-assisted content and subject-line generation, marketing automation for common small-business scenarios such as welcome series, abandoned-cart reminders, re-engagement campaigns, birthday messages, and post-purchase follow-ups, SMS/text marketing that can be coordinated alongside email sends, landing pages and website sign-up forms or pop-ups for lead capture, social media post scheduling, and (on higher tiers) Google and Facebook ad management plus basic SEO tools. As of 2026, Constant Contact's pricing is structured in three tiers, all starting at a base of 500 contacts: Lite at $12/month, which includes one user, core email sending, and a single automation template; Standard at $35/month, which adds up to three users, full marketing automation, A/B testing, and social media scheduling; and Premium at $80/month, which includes unlimited users, advanced automation, Google and Facebook ad management, and SEO tools. Pricing scales with contact list size rather than staying fixed — for example, published estimates put a 2,500-contact Standard plan around $70/month, while a 5,001-10,000 contact range costs roughly $120/month (Lite), $160/month (Standard), and $275/month (Premium). Constant Contact does not offer a permanent free plan; instead it offers a free trial period before billing begins. Its primary competitors in the small-business and nonprofit email marketing space include Mailchimp, ActiveCampaign, and Campaign Monitor, with Constant Contact generally differentiated by its long operating history, extensive live customer support options, and simplicity aimed at users without prior email marketing or design experience, rather than by advanced segmentation or automation depth.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'd46e98c7-b182-4988-9c3a-b509b0e2beff';

